-- Name: settlement_closings_settlement_closing_id_seq; Type: SEQUENCE; Schema: stl; Owner: -
--

ALTER TABLE stl.settlement_closings ALTER COLUMN settlement_closing_id ADD GENERATED ALWAYS AS IDENTITY (
    SEQUENCE NAME stl.settlement_closings_settlement_closing_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: settlement_lines; Type: TABLE; Schema: stl; Owner: -
--

CREATE TABLE stl.settlement_lines (
    settlement_line_id bigint NOT NULL,
    settlement_line_uid uuid DEFAULT public.gen_random_uuid() NOT NULL,
    tenant_id bigint NOT NULL,
    settlement_id bigint NOT NULL,
    line_seq integer NOT NULL,
    line_type character varying(50) NOT NULL,
    line_name character varying(200) NOT NULL,
    quantity numeric(18,3) DEFAULT 1 NOT NULL,
    unit_price numeric(18,4) DEFAULT 0 NOT NULL,
    supply_amount numeric(18,2) DEFAULT 0 NOT NULL,
    vat_amount numeric(18,2) DEFAULT 0 NOT NULL,
    total_amount numeric(18,2) DEFAULT 0 NOT NULL,
    rate_source jsonb DEFAULT '{}'::jsonb NOT NULL,
    adjustment_reason text,
    created_by bigint,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    updated_by bigint,
    deleted_at timestamp with time zone,
    deleted_by bigint
);


--
-- Name: settlement_lines_settlement_line_id_seq; Type: SEQUENCE; Schema: stl; Owner: -
--

ALTER TABLE stl.settlement_lines ALTER COLUMN settlement_line_id ADD GENERATED ALWAYS AS IDENTITY (
