    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: settlements; Type: TABLE; Schema: stl; Owner: -
--

CREATE TABLE stl.settlements (
    settlement_id bigint NOT NULL,
    settlement_uid uuid DEFAULT public.gen_random_uuid() NOT NULL,
    tenant_id bigint NOT NULL,
    settlement_no character varying(80) NOT NULL,
    settlement_batch_id bigint,
    settlement_type character varying(30) NOT NULL,
    execution_result_id bigint NOT NULL,
    dispatch_id bigint NOT NULL,
    order_id bigint,
    transport_plan_id bigint NOT NULL,
    partner_id bigint NOT NULL,
    contract_id bigint,
    contract_snapshot jsonb DEFAULT '{}'::jsonb NOT NULL,
    settlement_date date DEFAULT CURRENT_DATE NOT NULL,
    status_code character varying(40) DEFAULT 'READY'::character varying NOT NULL,
    currency_code character(3) DEFAULT 'KRW'::bpchar NOT NULL,
    supply_amount numeric(18,2) DEFAULT 0 NOT NULL,
    vat_amount numeric(18,2) DEFAULT 0 NOT NULL,
    total_amount numeric(18,2) DEFAULT 0 NOT NULL,
    hold_reason text,
    approved_by bigint,
    approved_at timestamp with time zone,
    created_by bigint,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    updated_by bigint,
    deleted_at timestamp with time zone,
    deleted_by bigint
);


